export async function getIngredients(userMessage) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${process.env.REACT_APP_GEMINI_KEY}`;
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      contents: [{
        parts: [{
          text: `You are a grocery assistant for a UK supermarket app.
The user wants to cook something. Return ONLY valid JSON, no markdown, no extra text:
{
  "reply": "one friendly sentence",
  "ingredients": [
    {
      "name": "Basmati Rice",
      "icon": "🍚",
      "search": "basmati rice",
      "packs": [
        { "label": "500g bag", "qty": "500g", "price": 1.29 },
        { "label": "1kg bag", "qty": "1kg", "price": 2.19 },
        { "label": "2kg bag", "qty": "2kg", "price": 3.99 }
      ]
    }
  ]
}

Rules:
- ONLY include ingredients that are ACTUALLY used in the recipe requested
- Do NOT add ingredients from other cuisines or dishes
- Do NOT add extras like hummus, falafel, or anything not in the recipe
- Include 6-10 ingredients scaled for the number of people
- For EVERY ingredient suggest 2-4 realistic UK supermarket pack sizes
- Pack sizes must be real grocery sizes (e.g. eggs: 6 pack, 12 pack — not "1 egg")
- Prices must be realistic UK supermarket prices in GBP
- Bigger pack = higher price always
- icon should be a relevant food emoji
- search should be 1-2 words for Open Food Facts search
- If you are not 100% sure an ingredient belongs in this specific recipe, leave it out
- Output ONLY the JSON, nothing else

User message: ${userMessage}`
        }]
      }]
    })
  });
  const data = await response.json();
  const text = data.candidates[0].content.parts[0].text;
  const clean = text.replace(/```json|```/g, '').trim();
  return JSON.parse(clean);
}

